<script>
    document.getElementById('footer-newsletter-sign').addEventListener('click', function(e) {
        e.preventDefault();
        
        showGlobalLoader();
        let acceptRules = 0;
        if (document.getElementById('footer-newsletter-rules').checked){
            acceptRules = 1;
        }

        fetch('/sign-to-newsletter', { 
            method: 'POST',
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                'email': document.getElementById('footer-newsletter-email').value,
                'rules' : acceptRules
            })
        }).then(response => {
            if(response.ok){
                return response.json();  
            }
            throw new Error('Request failed!');
            hideGlobalLoader();
        }, networkError => {
            hideGlobalLoader();
        }).then(jsonResponse => {
            
            let errosPoints = document.getElementById('footer-newsletter-sign-errors');
            let sucessInfo = document.getElementById('footer-newsletter-sign-sucess');
            errosPoints.innerHTML = '';
            if (jsonResponse.status){
                errosPoints.innerHTML = '';
                errosPoints.classList.add('hidden');
                sucessInfo.classList.remove('hidden');
                
                document.getElementById('footer-newsletter-email').value = '';
            } else {
                errosPoints.classList.remove('hidden');
                sucessInfo.classList.add('hidden');
                for(let i=0; i<jsonResponse.errors.length; i++){
                    let newErrorLi = document.createElement("li");
                    newErrorLi.innerHTML = jsonResponse.errors[i];
                    errosPoints.appendChild(newErrorLi);
                }
            }
            
            setTimeout(() => {
                hideGlobalLoader();
            }, "350");
            //
        });
    });
</script>
